function ok = fTxtOutV02(fNam,ttlC,datC)%% save data in a spread sheet%% ok = fTxtOutV02(fNam,ttlC,dataC)%% fNam: file path% ttlC: title cell % datC: data cell, cell of strings%% Written by Kei Nakamura% 2010/8/19 ver.1: created% 2013/1/17 ver.2: cell of strings (for new control system) %  %% main[~,nmbClm] = size(datC);  % number of shot, number of columndatC = datC';   % need to transpose for fprintfss = fEscMakerV01('%s',nmbClm);fid=fopen(fNam,'w');fprintf(fid,ss,ttlC{1:nmbClm,2});fprintf(fid,ss,datC{:,:});ok = fclose(fid);
